(function (Scratch) {
  "use strict";
  if (!Scratch.extensions.unsandboxed) {
    throw new Error("This extension must be run unsandboxed");
  }
  /** @type {MediaRecorder|null} */
  let mediaRecorder = null;
  let recordedChunks = [];
  const icon = "data:image/svg+xml;base64,";
  class Recording {
    getInfo() {
      return {
        id: "webcarecorder",
        name: "Webcam Recorder",
        color1: "#CFCFCF",
        menuIconURI: icon,
        blockIconURI: icon,
        unsandboxed: true,
        blocks: [
        {
              opcode: "turnOnCamera",
              blockType: Scratch.BlockType.COMMAND,
              text: "turn camera [ON_OFF]",
              arguments: {
                ON_OFF: {
                  type: Scratch.ArgumentType.STRING,
                  menu: "onOffMenu",
                  defaultValue: "on"
                }
              }
            },
          {
            opcode: "startRecording",
            blockType: Scratch.BlockType.COMMAND,
            text: "Start recording",
            arguments: {},
          },
          {
            opcode: "stopRecording",
            blockType: Scratch.BlockType.COMMAND,
            text: "Stop recording",
            arguments: {},
          },
          {
            opcode: "stopRecordingAndDownload",
            blockType: Scratch.BlockType.COMMAND,
            text: "Stop recording and download with [name] as filename",
            arguments: {
              name: {
                type: Scratch.ArgumentType.STRING,
                defaultValue: "recording.mp4",
              },
            },
          },
          {
            opcode: "isRecording",
            blockType: Scratch.BlockType.BOOLEAN,
            text: "Recording?",
            arguments: {},
          },
        ],
         menus: {
            onOffMenu: ["on", "off"]
          }
      };
    }
	
async turnOnCamera(args) {
        const turnOn = args.ON_OFF === "on";
        if (turnOn) {
          if (!this.mediaStream) {
            try {
              this.mediaStream = await navigator.mediaDevices.getUserMedia({ video: true });
              this.videoElement = document.createElement("video");
              this.videoElement.srcObject = this.mediaStream;
              this.videoElement.play();
            } catch (error) {
              console.error("Error accessing the camera:", error);
            }
          }
        } else {
          this.turnOffCamera();
        }
      }
  
      turnOffCamera() {
        if (this.mediaStream) {
          this.mediaStream.getTracks().forEach(track => track.stop());
          this.videoElement.remove();
          this.videoElement = null;
          this.mediaStream = null;
        }
      }
	
    async startRecording() {
      recordedChunks = [];
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        console.error("The recording function is not supported by the browser");
        return;
      }
      try {
        if (!(await Scratch.canRecordVideo())) {
          throw new Error("VM denied permission");
        }
        const stream = await navigator.mediaDevices.getUserMedia({
          video: true,
        });
        mediaRecorder = new MediaRecorder(stream);
        mediaRecorder.addEventListener("dataavailable", function (e) {
          recordedChunks.push(e.data);
        });
        mediaRecorder.start();
        console.log("Start recording");
      } catch (e) {
        console.error("Could not start recording", e);
      }
    }
    stopRecording() {
      if (!mediaRecorder) {
        console.error("Recording not started");
        return;
      }
      console.log("Stop recording");
      mediaRecorder.stop();
      mediaRecorder = null;
      recordedChunks = [];
    }
    stopRecordingAndDownload({ name }) {
      if (!mediaRecorder) {
        console.error("Recording not started");
        return;
      }
      console.log("Stop recording");
      mediaRecorder.addEventListener("stop", function () {
        const blob = new Blob(recordedChunks, { type: "video/webm" });
        const url = URL.createObjectURL(blob);
        const downloadLink = document.createElement("a");
        downloadLink.href = url;
        downloadLink.download = name;
        document.body.appendChild(downloadLink);
        downloadLink.click();
        document.body.removeChild(downloadLink);
        URL.revokeObjectURL(url);
        recordedChunks = [];
      });
      mediaRecorder.stop();
      mediaRecorder = null;
    }
    isRecording() {
      return !!mediaRecorder;
    }
  }
  Scratch.extensions.register(new Recording());
})(Scratch);
//Originally an audio recorder by -SIPC-, modified by Gaia.